            grammarLesson("negation", ("Niet and geen", "Niet en geen", "Niet и geen"), ("Use geen before an indefinite noun. Use niet for many other negations.", "Gebruik geen voor een onbepaald zelfstandig naamwoord. Gebruik niet voor veel andere ontkenningen.", "Geen ставится перед неопределённым существительным. Niet используется во многих других отрицаниях."), ["Ik heb geen fiets.", "Ik kom niet vandaag."], "geen"),
            grammarLesson("articles", ("De, het, and een", "De, het en een", "De, het и een"), ("Dutch has de and het for 'the'. Een means 'a/an'. Learn articles with the noun.", "Nederlands heeft de en het voor bepaald lidwoord. Een betekent onbepaald. Leer lidwoorden met het woord.", "В нидерландском de и het означают определённый артикль. Een - неопределённый. Учите артикль вместе со словом."), ["de afspraak", "het adres", "een fiets"], "het"),
            grammarLesson("plural", ("Plural basics", "Meervoud basis", "Множественное число"), ("Common plurals end in -en or -s: afspraak-afspraken, tafel-tafels.", "Veel meervouden eindigen op -en of -s: afspraak-afspraken, tafel-tafels.", "Часто множественное число заканчивается на -en или -s: afspraak-afspraken, tafel-tafels."), ["afspraken", "documenten"], "afspraken"),
            grammarLesson("perfect-tense", ("Perfect tense basics", "Voltooide tijd basis", "Основы прошедшего времени"), ("At A2 you start seeing hebben/zijn + past participle: Ik heb gewerkt.", "Op A2 ziet u hebben/zijn + voltooid deelwoord: Ik heb gewerkt.", "На A2 появляется конструкция hebben/zijn + причастие: Ik heb gewerkt."), ["Ik heb gewerkt.", "Ik ben verhuisd."], "heb gewerkt")
        ])
    }

    private static func module(_ id: String, _ level: DutchLevel, _ title: (String, String, String), _ summary: (String, String, String), _ icon: String, _ aliases: [String], _ lessons: [DutchLesson]) -> DutchCourseModule {
        DutchCourseModule(id: id, level: level, title: l(title), summary: l(summary), icon: icon, lessons: lessons, sourceIds: ["cefr", "duo-exams"], updatedAt: updatedAt, searchAliases: aliases)
    }

    private static func practicalLesson(_ id: String, _ title: (String, String, String), _ explanation: (String, String, String), _ words: [(String, String, String)], _ phraseValues: [(String, String, String)], _ level: DutchLevel, _ exerciseId: String, _ prompt: (String, String, String), _ correct: String, _ sourceIds: [String], related: [DutchCourseRelatedDestination] = []) -> DutchLesson {
        lesson(id, title, explanation, words.map { vocab($0.0, $0.1, $0.2, "Ik gebruik \( $0.0 ) vandaag.", "Я использую слово \( $0.0 ) сегодня.", nil, [id]) }, phraseValues.map { phrase($0.0, $0.1, $0.2, ("Practical phrase", "Praktische zin", "Практическая фраза")) }, miniDialogues(for: id, phrases: phraseValues), [], [exercise(exerciseId, .multipleChoice, level, prompt, [correct, "Ik woon in Leiden.", "Waar is de trein?", "Dat weet ik niet."], correct, ("This phrase fits the situation.", "Deze zin past bij de situatie.", "Эта фраза подходит к ситуации."))], sourceIds, related)
    }

    private static func grammarLesson(_ id: String, _ title: (String, String, String), _ explanation: (String, String, String), _ examples: [String], _ correct: String) -> DutchLesson {
        lesson(id, title, explanation, [], [], [], [grammar("\(id)-note", title.0, title.1, title.2, explanation.0, explanation.1, explanation.2, examples)], [exercise("\(id)-q1", .grammarChoice, .a2, ("Choose the correct form or word.", "Kies de juiste vorm of het juiste woord.", "Выберите правильную форму или слово."), [correct, "de", "niet werken", "naar"], correct, ("This follows the A1-A2 grammar rule in the lesson.", "Dit volgt de A1-A2-regel uit de les.", "Это соответствует правилу A1-A2 из урока."))], ["cefr"], [])
    }

    private static func lesson(_ id: String, _ title: (String, String, String), _ explanation: (String, String, String), _ vocabulary: [DutchVocabularyItem], _ phrases: [DutchPhrase], _ dialogues: [DutchDialogue] = [], _ grammarNotes: [DutchGrammarNote], _ exercises: [DutchExercise], _ sourceIds: [String], _ related: [DutchCourseRelatedDestination] = []) -> DutchLesson {
        DutchLesson(id: id, title: l(title), explanation: l(explanation), vocabulary: vocabulary, phrases: phrases, dialogues: dialogues, grammarNotes: grammarNotes, exercises: exercises, sourceIds: sourceIds, relatedDestinations: related)
    }

    private static func vocab(_ nl: String, _ ru: String, _ en: String, _ exampleNl: String, _ exampleRu: String, _ pronunciationHint: String?, _ tags: [String]) -> DutchVocabularyItem {
        DutchVocabularyItem(id: nl.lowercased().replacingOccurrences(of: " ", with: "-"), nl: nl, ru: ru, en: en, exampleNl: exampleNl, exampleRu: exampleRu, pronunciationHint: pronunciationHint, tags: tags)
    }

    private static func phrase(_ nl: String, _ ru: String, _ en: String, _ context: (String, String, String)) -> DutchPhrase {
        DutchPhrase(id: nl.lowercased().replacingOccurrences(of: " ", with: "-"), nl: nl, ru: ru, en: en, context: l(context))
    }

    private static func grammar(_ id: String, _ enTitle: String, _ nlTitle: String, _ ruTitle: String, _ en: String, _ nl: String, _ ru: String, _ examples: [String]) -> DutchGrammarNote {
        DutchGrammarNote(id: id, title: l((enTitle, nlTitle, ruTitle)), explanation: l((en, nl, ru)), examples: examples)
    }

    private static func exercise(_ id: String, _ type: DutchExerciseType, _ level: DutchLevel, _ prompt: (String, String, String), _ options: [String], _ correctAnswer: String, _ explanation: (String, String, String)) -> DutchExercise {
        DutchExercise(id: id, type: type, level: level, prompt: l(prompt), options: options, correctAnswer: correctAnswer, explanation: l(explanation))
    }

    private static func related(_ id: String, _ title: (String, String, String), _ icon: String, _ destination: AppDestination) -> DutchCourseRelatedDestination {
        DutchCourseRelatedDestination(id: id, title: l(title), icon: icon, destination: destination)
    }

    private static func miniDialogues(for lessonID: String, phrases: [(String, String, String)]) -> [DutchDialogue] {
        guard let first = phrases.first else { return [] }
        let second = phrases.dropFirst().first ?? ("Dank u wel.", "Спасибо.", "Thank you.")
        return [
            DutchDialogue(
                id: "\(lessonID)-dialogue",
                title: l(("Mini-dialogue", "Minidialoog", "Мини-диалог")),
                lines: [
                    DutchDialogueLine(id: "\(lessonID)-dialogue-a", speaker: l(("You", "U", "Вы")), nl: first.0, translation: l((first.2, first.2, first.1))),
                    DutchDialogueLine(id: "\(lessonID)-dialogue-b", speaker: l(("Staff", "Medewerker", "Сотрудник")), nl: second.0, translation: l((second.2, second.2, second.1)))
                ]
            )
        ]
    }

    private static func source(_ id: String, _ en: String, _ nl: String, _ ru: String, _ url: String, _ type: String, _ language: String) -> DutchCourseSource {
        DutchCourseSource(id: id, title: l((en, nl, ru)), url: url, sourceType: type, language: language, retrievedAt: updatedAt, verified: true)
    }

    private static func l(_ value: (String, String, String)) -> KNMLocalizedString {
        KNMLocalizedString(en: value.0, nl: value.1, ru: value.2)
    }
}
